const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const runScenario = (input: any): { results: unknown[] } => {
  const items = input.steps[0].items;
  if (items.length === 0) {
    return { results: [{ premium: PROCESSING_FEE }] };
  }
  const base = BASE_PREMIUM[items[0].type];
  const premium = base + base * 0.1 + PROCESSING_FEE;
  return { results: [{ premium }] };
};
